import{_ as i,c as t,o,a5 as r,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.51: Bedrock Cross-Region Fix, OSC52 Clipboard Restore","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.51.md","filePath":"en/changelog/v1.1.51.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.51.md"};function s(d,a,l,h,c,p){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="v1-1-51-bedrock-cross-region-fix-osc52-clipboard-restore" tabindex="-1">v1.1.51: Bedrock Cross-Region Fix, OSC52 Clipboard Restore <a class="header-anchor" href="#v1-1-51-bedrock-cross-region-fix-osc52-clipboard-restore" aria-label="Permalink to “v1.1.51: Bedrock Cross-Region Fix, OSC52 Clipboard Restore”">​</a></h1><p><strong>Release Date</strong>: February 04, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This is a minor version fix, mainly resolving the prefix duplication issue for Bedrock cross-region inference models, restoring TUI OSC52 clipboard support, and fixing the headers double merge bug.</p><hr><h2 id="bug-fix-bedrock-cross-region-inference-model-prefix-duplication" tabindex="-1">Bug Fix: Bedrock Cross-Region Inference Model Prefix Duplication <a class="header-anchor" href="#bug-fix-bedrock-cross-region-inference-model-prefix-duplication" aria-label="Permalink to “Bug Fix: Bedrock Cross-Region Inference Model Prefix Duplication”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When using AWS Bedrock cross-region inference models, the model name would incorrectly have the prefix added twice, causing API call failures.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed the prefix duplication issue. Cross-region inference models now work properly.</p><hr><h2 id="bug-fix-provider-headers-double-merge" tabindex="-1">Bug Fix: Provider Headers Double Merge <a class="header-anchor" href="#bug-fix-provider-headers-double-merge" aria-label="Permalink to “Bug Fix: Provider Headers Double Merge”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>If a provider had authentication configured in multiple places, headers would be double-merged, potentially causing request anomalies.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Reverted the change that caused headers double merging. Authentication information is now handled correctly.</p><hr><h2 id="improvement-tui-restore-osc52-clipboard" tabindex="-1">Improvement: TUI Restore OSC52 Clipboard <a class="header-anchor" href="#improvement-tui-restore-osc52-clipboard" aria-label="Permalink to “Improvement: TUI Restore OSC52 Clipboard”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Restored direct support for OSC52 clipboard protocol in TUI.</p><h3 id="what-s-the-use" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>OSC52 is a terminal clipboard protocol that allows copying content to the local clipboard even in remote SSH sessions. If you frequently use OpenCode via SSH, this feature is very practical.</p><hr><h2 id="improvement-agents-md-config-directory-priority" tabindex="-1">Improvement: AGENTS.md Config Directory Priority <a class="header-anchor" href="#improvement-agents-md-config-directory-priority" aria-label="Permalink to “Improvement: AGENTS.md Config Directory Priority”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>The directory specified by <code>OPENCODE_CONFIG_DIR</code> environment variable is now prioritized for finding AGENTS.md files.</p><h3 id="what-s-the-use-1" tabindex="-1">What&#39;s the Use? <a class="header-anchor" href="#what-s-the-use-1" aria-label="Permalink to “What&#39;s the Use?”">​</a></h3><p>If you&#39;ve customized the config directory via environment variable, AGENTS.md will be read from that directory first instead of the default location.</p><hr><h2 id="improvement-built-in-agent-documentation" tabindex="-1">Improvement: Built-in Agent Documentation <a class="header-anchor" href="#improvement-built-in-agent-documentation" aria-label="Permalink to “Improvement: Built-in Agent Documentation”">​</a></h2><h3 id="what-s-updated-2" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-2" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Added official documentation for built-in Agents, helping users understand OpenCode&#39;s built-in Agent functionality.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using AWS Bedrock cross-region inference</td><td>✅ Highly Recommended</td></tr><tr><td>Using OpenCode via SSH</td><td>✅ Recommended</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',37),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Revert change that caused headers to be double merged if provider was authenticated in multiple places</li><li>Document the built-in agents</li><li>Prevent double-prefixing of Bedrock cross-region inference models (@sergical)</li><li>Prioritize OPENCODE_CONFIG_DIR for AGENTS.md (@lgladysz)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Restore direct OSC52 support</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Tighten up session padding-top for mobile (@DNGriffin)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=i(n,[["render",s]]);export{m as __pageData,b as default};
